function Greeting({ user }) {
  let content;

  if (user) {
    content = (
      <div>
        <h1>Welcome back, {user.name}!</h1>
        <p>Last login: {user.lastLogin}</p>
      </div>
    );
  } else {
    content = (
      <div>
        <h1>Hello, stranger!</h1>
        <a href="/login">Sign in</a>
      </div>
    );
  }

  return <main>{content}</main>;
}

function StatusBadge({ status }) {
  if (status === 'active') {
    return <span className="badge badge-green">Active</span>;
  }
  if (status === 'pending') {
    return <span className="badge badge-yellow">Pending</span>;
  }
  // Default
  return <span className="badge badge-gray">Inactive</span>;
}

function UserProfile({ user, isLoading, error }) {
  // Guard: still loading
  if (isLoading) {
    return <p>Loading…</p>;
  }

  // Guard: error occurred
  if (error) {
    return <p>Error: {error.message}</p>;
  }

  // Guard: no user (empty state)
  if (!user) {
    return <p>No user found.</p>;
  }

  // Happy path — reached only when user is available and not loading
  return (
    <div className="profile">
      <img src={user.avatarUrl} alt={user.name} />
      <h2>{user.name}</h2>
      <p>{user.bio}</p>
    </div>
  );
}

// AVOID — nested conditions are hard to read
function UserProfileNested({ user, isLoading, error }) {
  if (!isLoading) {
    if (!error) {
      if (user) {
        return (
          <div className="profile">
            <img src={user.avatarUrl} alt={user.name} />
          </div>
        );
      } else {
        return <p>No user found.</p>;
      }
    } else {
      return <p>Error: {error.message}</p>;
    }
  } else {
    return <p>Loading…</p>;
  }
}
// Each level of nesting adds cognitive overhead.

function Alert({ message }) {
  // Don't render anything if there's no message
  if (!message) return null;

  return (
    <div className="alert" role="alert">
      {message}
    </div>
  );
}

// In the parent — can always render Alert; it handles its own absence
function Checkout() {
  const [error, setError] = useState(null);
  return (
    <div>
      <Alert message={error} />  {/* renders nothing when error is null */}
      <CheckoutForm onError={setError} />
    </div>
  );
}

function TaskStatus({ status }) {
  switch (status) {
    case 'todo':
      return <span style={{ color: '#6b7280' }}>To do</span>;
    case 'in-progress':
      return <span style={{ color: '#f59e0b' }}>In progress</span>;
    case 'done':
      return <span style={{ color: '#22c55e' }}>Done</span>;
    case 'cancelled':
      return <span style={{ color: '#ef4444' }}>Cancelled</span>;
    default:
      return <span style={{ color: '#9ca3af' }}>Unknown</span>;
  }
}

// Equivalent with chained if/else if — noisier for many cases
function TaskStatusIf({ status }) {
  if (status === 'todo') return <span>To do</span>;
  if (status === 'in-progress') return <span>In progress</span>;
  if (status === 'done') return <span>Done</span>;
  if (status === 'cancelled') return <span>Cancelled</span>;
  return <span>Unknown</span>;
}
// Both work — choose the one that reads most clearly.

const STATUS_DISPLAY = {
  todo:        <span className="badge gray">To do</span>,
  'in-progress': <span className="badge yellow">In progress</span>,
  done:        <span className="badge green">Done</span>,
  cancelled:   <span className="badge red">Cancelled</span>,
};

function TaskStatus({ status }) {
  return STATUS_DISPLAY[status] ?? <span className="badge gray">Unknown</span>;
}

// Works well when the map is static (defined outside the component).
// If the display depends on props, use switch or if/else instead.

function ProductPage({ product, isLoading }) {
  // Guards for early exit
  if (isLoading) {
    return (
      <PageShell>
        <Spinner />
      </PageShell>
    );
  }

  if (!product) {
    return (
      <PageShell>
        <EmptyState message="Product not found" />
      </PageShell>
    );
  }

  // Happy path — full product display
  return (
    <PageShell>
      <h1>{product.name}</h1>
      <p>{product.description}</p>
      <Price amount={product.price} />
      <AddToCartButton productId={product.id} />
    </PageShell>
  );
}

function PageShell({ children }) {
  return (
    <main className="page-container">
      <Breadcrumb />
      {children}
      <Footer />
    </main>
  );
}

import { render, screen } from '@testing-library/react';

test('shows loading state', () => {
  render(<UserProfile isLoading={true} user={null} error={null} />);
  expect(screen.getByText(/loading/i)).toBeInTheDocument();
});

test('shows error state', () => {
  render(<UserProfile isLoading={false} user={null} error={{ message: 'Not found' }} />);
  expect(screen.getByText('Error: Not found')).toBeInTheDocument();
});

test('shows user profile when data is available', () => {
  const user = { name: 'Alice', avatarUrl: '/alice.jpg', bio: 'React dev' };
  render(<UserProfile isLoading={false} user={user} error={null} />);
  expect(screen.getByRole('heading', { name: 'Alice' })).toBeInTheDocument();
  expect(screen.getByText('React dev')).toBeInTheDocument();
});

test('Alert renders nothing when message is null', () => {
  const { container } = render(<Alert message={null} />);
  expect(container).toBeEmptyDOMElement();
});

test('Alert renders message', () => {
  render(<Alert message="Something went wrong" />);
  expect(screen.getByRole('alert')).toHaveTextContent('Something went wrong');
});

// Named states — no scattered booleans
const VIEW = {
  LOADING: 'loading',
  ERROR: 'error',
  EMPTY: 'empty',
  READY: 'ready',
};

function DataTable({ data, isLoading, error }) {
  // Determine the current view from props
  const view =
    isLoading ? VIEW.LOADING
    : error    ? VIEW.ERROR
    : data.length === 0 ? VIEW.EMPTY
    : VIEW.READY;

  // Single switch drives the whole conditional render
  if (view === VIEW.LOADING) return <TableSkeleton />;
  if (view === VIEW.ERROR)   return <ErrorPanel message={error.message} />;
  if (view === VIEW.EMPTY)   return <EmptyState />;  // null would hide it entirely

  // VIEW.READY — render the actual table
  return (
    <table>
      <thead>...</thead>
      <tbody>
        {data.map(row => <tr key={row.id}>...</tr>)}
      </tbody>
    </table>
  );
}

// WRONG — calling a hook inside an if block
function BrokenComponent({ showFeature }) {
  if (showFeature) {
    const [count, setCount] = useState(0); // ERROR: Rules of Hooks
    return <Counter count={count} />;
  }
  return <p>Feature disabled</p>;
}

// CORRECT — hooks always called, guard clause after them
function CorrectComponent({ showFeature }) {
  const [count, setCount] = useState(0); // always called

  if (!showFeature) {
    return <p>Feature disabled</p>;
  }

  return <Counter count={count} />;
}

// Alternatively: split into two components
function FeatureGate({ showFeature }) {
  if (!showFeature) return <p>Feature disabled</p>;
  return <FeatureContent />; // hooks live inside FeatureContent
}
function FeatureContent() {
  const [count, setCount] = useState(0); // safe — always rendered when called
  return <Counter count={count} />;
}

// Cart page — logged-in users see their cart, guests see a prompt
function CartPage({ user }) {
  if (!user) {
    return <GuestCartPrompt />;
  }
  return <AuthenticatedCart userId={user.id} />;
}

// GuestCartPrompt has its own state (promo code hover, etc.)
function GuestCartPrompt() {
  const [promoVisible, setPromoVisible] = useState(false);
  return (
    <div>
      <h2>Your cart is empty</h2>
      <a href="/login">Sign in to view saved items</a>
      {promoVisible && <p>Use code WELCOME10 for 10% off!</p>}
      <button onClick={() => setPromoVisible(true)}>Get promo code</button>
    </div>
  );
}

// AuthenticatedCart has its own state (quantities, etc.)
function AuthenticatedCart({ userId }) {
  const [items, setItems] = useState([]);
  useEffect(() => { fetchCart(userId).then(setItems); }, [userId]);
  if (items.length === 0) return <EmptyCart />;
  return <CartItemList items={items} onChange={setItems} />;
}
// Each branch has its own hooks — no violations of Rules of Hooks.

// CSS hiding — element stays in DOM and accessibility tree
// Only appropriate when you WANT to preserve state (e.g. a tab panel)
function TabPanel({ isActive, children }) {
  return (
    <div
      role="tabpanel"
      hidden={!isActive}  // HTML hidden attribute — semantic + CSS
      aria-hidden={!isActive}
    >
      {children}
    </div>
  );
}

// Conditional rendering — element unmounts when hidden
// Use when you DON'T need to preserve state
function Drawer({ isOpen, children }) {
  if (!isOpen) return null;
  return (
    <div role="dialog" aria-modal="true">
      {children}
    </div>
  );
}
